import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
  const [shows, setShows] = useState([]);
  const [modalImage, setModalImage] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadShows = async () => {
      try {
        // Tentar diferentes caminhos para o JSON
        let response;
        try {
          response = await fetch('./data/shows.json');
        } catch {
          response = await fetch('/data/shows.json');
        }

        if (response.ok) {
          const showsData = await response.json();

          // Filtrar shows futuros
          const hoje = new Date();
          hoje.setHours(0, 0, 0, 0);

          const showsFuturos = showsData.filter(show => {
            const [ano, mes, dia] = show.data_fim.split('-');
            const dataFim = new Date(ano, mes - 1, dia);
            dataFim.setHours(0, 0, 0, 0);
            return dataFim >= hoje;
          });

          // Ordenar por data
          showsFuturos.sort((a, b) => new Date(a.data_inicio) - new Date(b.data_inicio));

          setShows(showsFuturos);
        } else {
          console.error('Erro ao carregar shows.json');
        }
      } catch (error) {
        console.error('Erro:', error);
      }

      setLoading(false);
    };

    loadShows();
  }, []);

  const formatarData = (dataISO) => {
    if (!dataISO) return '';
    const [ano, mes, dia] = dataISO.split('-');
    return `${dia}/${mes}/${ano}`;
  };

  const mostrarData = (show) => {
    if (show.data_inicio === show.data_fim) {
      return formatarData(show.data_inicio);
    } else {
      return `${formatarData(show.data_inicio)} a ${formatarData(show.data_fim)}`;
    }
  };

  const abrirModal = (imageSrc) => {
    setModalImage(imageSrc);
    setIsModalOpen(true);
  };

  const fecharModal = () => {
    setIsModalOpen(false);
    setModalImage('');
  };

  // Fechar modal com ESC
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape' && isModalOpen) {
        fecharModal();
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [isModalOpen]);

  if (loading) {
    return (
      <div className="App">
        <h1>Agenda de Shows</h1>
        <div className="loading">Carregando...</div>
      </div>
    );
  }

  return (
    <div className="App">
      <h1>Agenda de Shows</h1>

      <div className="shows-list">
        {shows.length === 0 ? (
          <p className="no-shows">Nenhum show cadastrado no momento.</p>
        ) : (
          shows.map((show, index) => (
            <div key={index} className="show-card">
              <img 
                src={show.flyer.startsWith('/') ? `.${show.flyer}` : show.flyer}
                alt={`Show de ${show.artista}`}
                onClick={() => abrirModal(show.flyer.startsWith('/') ? `.${show.flyer}` : show.flyer)}
                onError={(e) => {
                  console.log('Erro na imagem:', show.flyer);
                  e.target.style.display = 'none';
                }}
              />
              <div className="show-info">
                <h2>{show.artista}</h2>
                <p><strong>Data:</strong> {mostrarData(show)}</p>
                <p><strong>Local:</strong> {show.local}</p>
                <p><strong>Cidade:</strong> {show.cidade}</p>
              </div>
            </div>
          ))
        )}
      </div>

      {isModalOpen && (
        <div className="image-modal" onClick={fecharModal}>
          <span className="close-modal">&times;</span>
          <img 
            src={modalImage} 
            alt="Imagem ampliada"
            onClick={(e) => e.stopPropagation()}
          />
        </div>
      )}
    </div>
  );
}

export default App;
